// Filtrér: kun sager fra de sidste 7 dage med relevans >= 3
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const allItems = $input.all().map(i => i.json);

const relevant = allItems.filter(s => {
  const score = parseInt(s.relevans_score) || 0;
  if (score < 3) return false;

  // Tjek om sagen er nyere end 7 dage
  const created = new Date(s.oprettet);
  return created >= weekAgo;
});

// Sortér efter relevans (højest først)
relevant.sort((a, b) => (parseInt(b.relevans_score) || 0) - (parseInt(a.relevans_score) || 0));

if (relevant.length === 0) {
  return [{ json: { skip: true, besked: 'Ingen nye relevante sager denne uge.' } }];
}

return [{ json: { skip: false, sager: relevant, antal: relevant.length } }];

