// Udtræk HTML fra Claude-svar
const aiResponse = $input.first().json;
let html = '';
try {
  html = aiResponse.content?.[0]?.text || aiResponse.text || '<p>Kunne ikke generere briefing.</p>';
  // Fjern eventuelle markdown code blocks
  html = html.replace(/```html\n?/g, '').replace(/```\n?/g, '').trim();
} catch (e) {
  html = '<p>Fejl ved generering af briefing: ' + e.message + '</p>';
}

return [{ json: { html, subject: `VisitMiddelfart – Ugentlig politisk briefing (uge ${Math.ceil((new Date().getDate()) / 7)})` } }];
